var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"WIND_VARUNA_SHADOW_NULL","text":{"KOREA":"결국 운명의 끝은 정해져 있는 거야. 아디트야.","JPN":"結局運命の果ては定められているのだ。アーディティヤ。","ENG":"The end of fate is decided in the end, Aditya.","TWN":"你的最終命運是註定的，阿迪亞。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_SHADOW_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"당신은 숭고한 임무를 져버리고 도망쳤습니다.","JPN":"あなたは崇高な任務を見捨て、逃げました。","ENG":"You have abandoned your noble mission and fled.","TWN":"你放棄崇高的任務落荒而逃。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"WIND_VARUNA_SHADOW_NULL","text":{"KOREA":"하지만 아직 약속을 지킬 수 있어. 아주 간단한 방법이지.","JPN":"でもまだ約束は守れる。とても簡単な方法だ。","ENG":"But you can still keep your promise. We can offer you a simple solution.","TWN":"但你還能遵守約定，有個非常簡單的方法。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_SHADOW_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"하지만 아직 당신에게 구원의 손길이 남아 있습니다.","JPN":"ですが、まだあなたに救いの道は残っています。","ENG":"There is still salvation for you.","TWN":"你還有救贖的機會。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"어서.","JPN":"早く。","ENG":"Go.","TWN":"來。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"WIND_VARUNA_NULL_GIRL","text":{"KOREA":"어서.","JPN":"早く。","ENG":"Go.","TWN":"來。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"<color=#ff3636>우리를 완성하도록 해요. </color>","JPN":"<color=#ff3636>私たちを完成してください。</color>","ENG":"<color=#ff3636>Go complete us.</color>","TWN":"<color=#ff3636>讓我們完整吧。</color>"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"……!","JPN":"……！","ENG":"...!","TWN":"……！"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L29_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"환각이 점점 강해지고 있다.","JPN":"どんどん幻覚がひどくなっている。","ENG":"The hallucinations are getting worse.","TWN":"幻覺越來越嚴重了。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"침식파의 영향인가? 워치의 초침도 이제 곧 한계야.","JPN":"侵食波の影響か？　ウォッチの針ももうすぐ限界だ。","ENG":"Is it the effect of the Corruption rays? The Watch's second hand will soon reach its limit.","TWN":"是侵蝕波的影響嗎？能量環也快到極限了。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"그렇다면…… 적어도 너 하나는 반드시…….","JPN":"ならば……少なくとも君だけは必ず……","ENG":"Then... I must at least...","TWN":"那……至少要和你一起……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L37_1","type":"narration","speaker":null,"text":{"KOREA":"힘이 내 몸을 불태울 만큼 폭주하기 시작하고.","JPN":"力が自分の体を燃え尽くすほどに暴走し始め。","ENG":"The power started to run rampant, enough to burn my body.","TWN":"足以燃燒我身體的力量開始暴走。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"narration","speaker":null,"text":{"KOREA":"녀석은 그 모습을 보곤 황홀한 듯 입을 쩍 벌린 채 굶주린 짐승처럼 다가온다.","JPN":"やつはその姿を見てうっとりとしたように口を大きく開けては飢えた獣のごとく近づいてくる。","ENG":"The thing sees me and starts approaching me with its mouth open in raptus like a starving beast.","TWN":"那個傢伙張大嘴巴，像饑餓的野獸一樣靠近。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"narration","speaker":null,"text":{"KOREA":"나를 향한 망집. 침식체는 제 몸이 모두 불타더라도 단 하나의 욕망을 위해 움직인다.","JPN":"私への妄執。侵食体は自分の身が燃え尽きようと、ただ一つの欲望のために動く。","ENG":"Its obsession headed toward me. The C.O. moves for its one desire, even if it means setting its entire body on fire.","TWN":"那是對於我的妄念。即使吞下焚身的烈焰，它也會為唯一的欲望而行動。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"narration","speaker":null,"text":{"KOREA":"인도하는 태양과 영원히 함께하는 것.","JPN":"導く太陽と永遠に共にすること。","ENG":"To be with the guiding sun forever.","TWN":"就是與引導之陽永遠相伴。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"자, 입을 벌려라. 바루나스트라.","JPN":"さあ、口を開けろ。ヴァルナストラ。","ENG":"Now, open wide, Varunastra.","TWN":"來，再張大些，伐樓拿之艦。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_ELECTRIC_ATTACK_BIG_02"},{"id":"L47_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"내 모든 가능성을 연료 삼아 너의 모든 것을 불태워주겠다.","JPN":"私のすべての可能性を燃料にし、君のすべてを燃え尽くしてやろう。","ENG":"I will use all my possibilities as fuel to set you on fire.","TWN":"用我所有的可能性作為燃料，燃燒你的一切。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"narration","speaker":null,"text":{"KOREA":"탐욕스러운 고래가 나를 향해 입을 벌렸을 때.","JPN":"貪欲なクジラが私に向かって口を開けた瞬間、","ENG":"When the greedy whale opened its mouth toward me.","TWN":"貪婪的鯨魚向我張開嘴巴。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"narration","speaker":null,"text":{"KOREA":"나는 여전히 내 모습이 과거에 머물러 있음을 깨달았다.","JPN":"私は自分の姿が今でも過去に留まっているということに気付いた。","ENG":"I realized that I was still stuck in the past.","TWN":"我意識到自己依然被困在過去。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"narration","speaker":null,"text":{"KOREA":"더 이상 잃을 것이 없는 내가 기꺼이 내놓을 수 있는 것은.","JPN":"もう失うものなどない私が喜んで差し出せるものは、","ENG":"All that I could gladly offer, after having nothing more to lose.","TWN":"只不過這一次，我已經沒有什麼可以失去。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"여전히, 그저 불타 없어질 목숨뿐이란 것을.","JPN":"相変わらず、ただ燃えて無くなる命だけだということに。","ENG":"That was still my life that will burn to ashes.","TWN":"能獻的，只有會燃燒殆盡的生命而已。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"처음 보는. 그러나 익숙하고도 그리운 곳이 떠오른다.","JPN":"初めて見るけれど、どこか見慣れて懐かしい場所が思い浮かぶ。","ENG":"A place I've never seen before, but also a place that feels both familiar and nostalgic.","TWN":"腦海中自然而然地浮現出熟悉而懷念的地方。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"narration","speaker":null,"text":{"KOREA":"언젠가, 모두가 모여 웃고 울며, 미래를 꿈꾸었던 것 같았던 곳.","JPN":"いつか皆が集まり、笑って泣いて、未来を夢見ていたような場所。","ENG":"A place where everyone would gather, sharing joys and sorrows and hoping for a better future.","TWN":"曾幾何時，大家聚在一起歡笑、哭泣，憧憬著未來……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"narration","speaker":null,"text":{"KOREA":"점차 색이 옅어지듯, 기억도 옅어진다.","JPN":"どんどん色あせるように、記憶も薄れてゆく。","ENG":"Just like colors gradually fading away, so do my memories.","TWN":"原來記憶也會像顏色一樣逐漸褪色……"},"stage":{"bg":"VARUNA_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"narration","speaker":null,"text":{"KOREA":"어김없이 들려오는, 기억나지 않는 이들의 목소리가 들려온다.","JPN":"またしても、思い出せない者たちの声が聞こえてくる。","ENG":"I hear the voices of those I can't remember, without fail.","TWN":"耳邊一如既往地傳來那些記不得的人的聲音。"},"stage":{"bg":"VARUNA_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"narration","speaker":null,"text":{"KOREA":"난 이 칠흑 같은 어둠 속을 영원히 헤매게 되는 것일까?","JPN":"私はこの漆黒のような闇の中で永遠に彷徨うことになるのだろうか。","ENG":"Will I wander for an eternity in the pitch-black darkness?","TWN":"難道我會永遠在這片漆黑中徘徊嗎？"},"stage":{"bg":"VARUNA_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"narration","speaker":null,"text":{"KOREA":"어두운 건 싫다. 결국 혼자가 될 것이라는 운명도 싫어.","JPN":"暗いのは嫌いだ。結局一人になるという運命も嫌いだ。","ENG":"I don't like the dark. I also hate my fate of ending up alone.","TWN":"我討厭黑暗，也討厭註定要孤獨一人的命運。"},"stage":{"bg":"VARUNA_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"narration","speaker":null,"text":{"KOREA":"아주 작은 빛이라도 좋아. 이 어둠을 몰아낼 수만 있다면…….","JPN":"ほんの小さな光でもいい。この闇を灯すことができるのなら……","ENG":"A tiny ray of light would be enough. If I can drive away this darkness...","TWN":"即使是微弱的光芒也好，只要能驅散這陣黑暗……"},"stage":{"bg":"VARUNA_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"괜찮아요? 제 목소리 들리세요?","JPN":"大丈夫ですか？　私の声が聞こえますか？","ENG":"Are you okay? Can you hear me?","TWN":"沒事吧？能聽到我的聲音嗎！"},"stage":{"bg":"VARUNA_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"narration","speaker":null,"text":{"KOREA":"이 목소리는…….","JPN":"この声は……","ENG":"This voice...","TWN":"這聲音是……"},"stage":{"bg":"VARUNA_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"갑자기 나침반이 작동하더라니! 아디트야 님이……!","JPN":"いきなり羅針盤が作動すると思ったら、アーディティヤ様が……！","ENG":"The compass was suddenly working! And Miss Aditya was...!","TWN":"指南針突然動了！是阿迪亞嗎……！"},"stage":{"bg":"VARUNA_03","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"밖이 보여요! 역시…… 저 빛은……!","JPN":"外が見えます！　やっぱり……あの光は……！","ENG":"I see the outside! I knew it... that light is...!","TWN":"看到外面了！果然……那道光是……！"},"stage":{"bg":"VARUNA_03","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"더 빨리요! 아디트야 님이 위험해요!","JPN":"もっと早く！　アーディティヤ様が危険です！","ENG":"Quickly! Miss Aditya is in danger!","TWN":"快！阿迪亞有危險！"},"stage":{"bg":"VARUNA_03","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"어쩌면…….","JPN":"もしかしたら……","ENG":"Perhaps...","TWN":"也許……"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"작은 빛은 이미 찾은 걸지도 모르겠어.","JPN":"小さな光は、すでに見つけたのかもしれない。","ENG":"I have already found that tiny light.","TWN":"也許我已經找到那微弱的光芒。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"아디트야 님! 저 아직 살아 있었어요!","JPN":"アーディティヤ様！　私、まだ生きてました！","ENG":"Miss Aditya! I'm still alive!","TWN":"阿迪亞！我還活著！"},"stage":{"bg":"VARUNA_03","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그러니 죄책감 가지지 마세요!","JPN":"だから、罪悪感なんて感じなくてもいいんです！","ENG":"So don't feel guilty!","TWN":"你不需要愧疚！"},"stage":{"bg":"VARUNA_03","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"아하하…… 원래도 CRF 제어가 서투르셨는데, 여전하시군요.","JPN":"あはは……もとからCRF制御が下手でしたが、相変わらずですね。","ENG":"Ah hah hah... She was always bad with controlling her CRF. I guess she's still the same.","TWN":"呵呵呵……你一向不擅長控制CRF，看來還是老樣子呢。"},"stage":{"bg":"VARUNA_03","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_VARUNA_C_WIND_IN_TRAILER_1"},{"id":"L41_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"그동안 혼자 모든 걸 감당하게 해서 죄송해요.","JPN":"一人ですべてを背負わせてしまい、申し訳ありません。","ENG":"I'm sorry for making you handle everything on your own.","TWN":"這段時間讓你一個人承擔一切，真是抱歉。"},"stage":{"bg":"VARUNA_03","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_VARUNA_C_WIND_IN_TRAILER_2"},{"id":"L42_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"아직 제가 받은 은혜를 다 갚지 못했는데, 여기서 돌아가시게 둘 순 없죠.","JPN":"まだ私が受けた恩をすべて返せていないのに、こんな終わり方なんて納得できません。","ENG":"I still haven't repaid you for everything, so I can't let you die here.","TWN":"但我還沒有報答你的恩情，不能讓你就這麼離開。"},"stage":{"bg":"VARUNA_03","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_VARUNA_C_WIND_IN_TRAILER_3"},{"id":"L43_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"그래서 어떻게든…… 살아 있었어요.","JPN":"だから、どうにか……生き延びていました。","ENG":"That's why... I had to live.","TWN":"這是我無論如何……想要活著的理由。"},"stage":{"bg":"VARUNA_03","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_VARUNA_C_WIND_IN_TRAILER_4"},{"id":"L44_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"손을 잡으세요! 이번엔 제가 약속을 지킬 차례예요!","JPN":"私の手を掴んでください！　今度は私が約束を守る番です！","ENG":"Take my hand! It's my turn to keep my promise!","TWN":"請握住我的手！這次輪到我來履行約定！"},"stage":{"bg":"VARUNA_03","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_VARUNA_C_WIND_IN_TRAILER_5"},{"id":"L45_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"반드시 당신과 함께하겠다고!","JPN":"必ずあなたと共にいるという約束を！","ENG":"The promise that I'll be with you!","TWN":"我說過會等你的！"},"stage":{"bg":"VARUNA_03","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_VARUNA_C_WIND_IN_TRAILER_6"},{"id":"L46_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"……!","JPN":"……！","ENG":"...!","TWN":"……！"},"stage":{"bg":"VARUNA_03","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"침식체 반응 확인! 땅속에서 올라오고 있습니다!","JPN":"侵食体の反応を確認！　地中から上がってきます！","ENG":"C.O. detected! It's coming up from the ground!","TWN":"確認到侵蝕體反應！從地下來的！"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"침식파 밀도가 급격하게 상승하고 있습니다! 이대로 있으면 모두 전멸이에요!","JPN":"侵食波の密度が急激に上昇中！　このままだと全滅です！","ENG":"Corruption ray density is rapidly increasing! We will be wiped out at this rate!","TWN":"侵蝕波密度正在急速上升！這樣下去的話，大家會死的！"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"하지만…… 분명 모든 가능성을 검토했어요. 인과율 계산이 어긋났다는 것은…….","JPN":"しかし……あらゆる可能性は検証済みです。因果律計算が狂ったということは……","ENG":"But... we've already checked every possibility. If the causality calculation is off, then...","TWN":"但是……我已經檢查過所有的可能性。如果因果率計算出錯……"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"언제가 됐든 저는 기다릴게요. 그러니 그런 표정 짓지 마세요.","JPN":"そんな顔しなくてもいいですよ。いつまでも待ってますから。","ENG":"I'll be waiting for you, no matter how long it takes. So, don't make that face.","TWN":"無論什麼時候，我都會等你的。所以不要露出那樣的表情。"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"빛이…… 줄어들고 있어요.","JPN":"光が……弱まっています。","ENG":"The light... is getting smaller.","TWN":"光……減弱了。"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L20_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"아하하. 기억을 잃으셨다고 했지. 참.","JPN":"あはは。記憶を失ったのでしたよね。そうでした。","ENG":"Ah hah hah. I heard you lost your memories.","TWN":"呵呵呵，你失去記憶了對吧。"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"무리한 부탁일지도 모르지만…… 제 이름을 불러 주실 수 있으실까요?","JPN":"無理なお願いかもしれませんが……私の名前を呼んでもらえませんか？","ENG":"I might be asking for too much, but... could you say my name?","TWN":"這個要求可能有些過分……但能叫一聲我的名字嗎？"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"직접…… 듣고 싶었거든요.","JPN":"直接……聞きたかったのです。","ENG":"I want... to hear it from you directly.","TWN":"因為……我想親耳聽到你叫我。"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"내가 지어준 이름을…… 어떻게 잊을 수 있겠어.","JPN":"私が付けた名前を……忘れるはずがないだろう？","ENG":"How can I ever forget... the name I gave you?","TWN":"我怎麼會忘記呢……那是我給你取的名字……"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"……아닐라. \xA0","JPN":"……アニラ。\xA0 ","ENG":"...Anila.\xA0","TWN":"……雅妮拉。"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};